- "economic size" refers to GDP;
- "people count" refers to population;
- "financial details were last accessed" refers to the access date of the revenue data.

sql:
SELECT SUM(national_revenue) AS total_national_revenue
FROM government_revenues
WHERE revenue_type = 'non-tax' AND year > 2000;

SELECT year, AVG(national_revenue) AS avg_national_revenue
FROM government_revenues
GROUP BY year;

SELECT AVG(population)
FROM entities
WHERE population > (
  SELECT AVG(population)
  FROM entities
);

SELECT document_title 
FROM policy_documents 
WHERE document_year = 2023;

